// Generates resources/js/types/api/schemas.ts: a flat alias per API Resource schema,
// so frontend code can write `User` instead of `components['schemas']['User']`.
// Run via `npm run generate:types` (chained after openapi-typescript). Do not edit schemas.ts by hand.

import { readFileSync, writeFileSync } from 'node:fs';

const specPath = process.argv[2] ?? '/tmp/api-spec.json';
const outPath = 'resources/js/types/api/schemas.ts';

const spec = JSON.parse(readFileSync(specPath, 'utf8'));
const schemas = spec.components?.schemas ?? {};
const names = Object.keys(schemas).sort();

const isValidIdentifier = (name) => /^[A-Za-z_$][A-Za-z0-9_$]*$/.test(name);

const lines = [
    '// AUTO-GENERATED by `npm run generate:types`. Do not edit by hand.',
    "// Flat aliases for every API Resource schema (e.g. `import type { User } from '@/types/api/schemas'`).",
    '',
    "import type { components } from './index';",
    '',
    ...names.map((name) =>
        isValidIdentifier(name)
            ? `export type ${name} = components['schemas']['${name}'];`
            : `// skipped schema with non-identifier name: ${JSON.stringify(name)}`,
    ),
    '',
];

writeFileSync(outPath, lines.join('\n'));
console.log(`Wrote ${names.length} schema alias(es) to ${outPath}`);
